Load declarative configuration from YAML or TOML files with validation.

## Implementation

```rust
// src/config/loader.rs
use std::path::Path;
use tracing::{debug, info, warn, instrument};

#[derive(Debug, Clone)]
pub enum ConfigFormat {
    Yaml,
    Toml,
}

impl ConfigFormat {
    pub fn from_extension(path: &Path) -> Option<Self> {
        match path.extension()?.to_str()? {
            "yaml" | "yml" => Some(Self::Yaml),
            "toml" => Some(Self::Toml),
            _ => None,
        }
    }
}

/// Load and parse a configuration file
#[instrument(fields(path = %path.display()))]
pub fn load_config(path: &Path) -> Result<ProfileConfig, ConfigError> {
    info!("Loading configuration file");

    // Detect format
    let format = ConfigFormat::from_extension(path)
        .ok_or_else(|| ConfigError::UnknownFormat(path.to_path_buf()))?;
    debug!(format = ?format, "Detected config format");

    // Read file
    let content = std::fs::read_to_string(path)
        .map_err(|e| ConfigError::ReadError(path.to_path_buf(), e))?;
    debug!(bytes = %content.len(), "Read config file");

    // Parse based on format
    let config: ProfileConfig = match format {
        ConfigFormat::Yaml => {
            serde_yaml::from_str(&content)
                .map_err(|e| ConfigError::ParseError(format!("YAML: {}", e)))?
        }
        ConfigFormat::Toml => {
            toml::from_str(&content)
                .map_err(|e| ConfigError::ParseError(format!("TOML: {}", e)))?
        }
    };

    // Validate
    config.validate()?;

    info!(
        keys = %config.keys.len(),
        brightness = ?config.brightness,
        "Configuration loaded successfully"
    );

    Ok(config)
}

#[derive(Debug, Clone, serde::Deserialize)]
pub struct ProfileConfig {
    /// Optional profile name
    pub name: Option<String>,
    /// Target device serial (optional)
    pub device: Option<String>,
    /// Brightness level (0-100)
    pub brightness: Option<u8>,
    /// Key configurations
    #[serde(default)]
    pub keys: Vec<KeyConfig>,
}

impl ProfileConfig {
    pub fn validate(&self) -> Result<(), ConfigError> {
        // Validate brightness range
        if let Some(b) = self.brightness {
            if b > 100 {
                return Err(ConfigError::ValidationError(
                    format!("brightness {} out of range (0-100)", b)
                ));
            }
        }

        // Validate each key config
        for key in &self.keys {
            key.validate()?;
        }

        Ok(())
    }
}
